+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+import applyStyles from './styles.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fr'; factor: number; min: number}
+	| {type: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const parseTrack = (value: string): Track | undefined => {
+	if (value === 'auto') return {type: 'auto'};
+	const fixed = Number(value);
+	if (Number.isFinite(fixed) && fixed >= 0) return {type: 'fixed', size: fixed};
+	const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fr) return {type: 'fr', factor: Number(fr[1]), min: 0};
+	const minmax = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?(?:fr)?)\\s*\\)$/.exec(value);
+	if (!minmax) return undefined;
+	const min = Number(minmax[1]);
+	return minmax[2].endsWith('fr')
+		? {type: 'fr', factor: Number.parseFloat(minmax[2]), min}
+		: {type: 'fixed', size: Number(minmax[2])};
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	(template?.match(/minmax\\([^)]*\\)|[^\\s]+/g) ?? []).flatMap(value => {
+		const track = parseTrack(value);
+		return track ? [track] : [];
+	});
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+	if (typeof value !== 'string') return undefined;
+	const parts = value.split('/').map(part => Number(part.trim()));
+	if (parts.length === 1 && Number.isInteger(parts[0]) && parts[0] > 0) {
+		return {start: parts[0] - 1, end: parts[0]};
+	}
+	if (parts.length === 2 && parts.every(part => Number.isInteger(part) && part > 0) && parts[1] > parts[0]) {
+		return {start: parts[0] - 1, end: parts[1] - 1};
+	}
+};
+
+const resolveTracks = (tracks: Track[], available: number, autoSizes: number[]): number[] => {
+	const sizes = tracks.map((track, index) => track.type === 'fixed' ? track.size : track.type === 'auto' ? (autoSizes[index] ?? 0) : track.min);
+	const remaining = Math.max(0, available - sizes.reduce((total, size) => total + size, 0));
+	const factors = tracks.reduce((total, track) => total + (track.type === 'fr' ? track.factor : 0), 0);
+	return sizes.map((size, index) => tracks[index].type === 'fr' && factors > 0 ? size + remaining * tracks[index].factor / factors : size);
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const result = offset;
+		offset += size + gap;
+		return result;
+	});
+};
+
+const spanSize = (sizes: number[], start: number, end: number, gap: number): number =>
+	sizes.slice(start, end).reduce((total, size) => total + size, 0) + Math.max(0, end - start - 1) * gap;
+
+const isGrid = (node: DOMElement): boolean => node.style.display === 'grid';
+
+const resetGridItem = (node: DOMElement): void => {
+	if (!node.internal_gridItem || !node.yogaNode) return;
+	node.yogaNode.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+	node.yogaNode.setWidthAuto();
+	node.yogaNode.setHeightAuto();
+	node.yogaNode.setPosition(Yoga.EDGE_LEFT, 0);
+	node.yogaNode.setPosition(Yoga.EDGE_TOP, 0);
+	applyStyles(node.yogaNode, node.style, node.style);
+	node.internal_gridItem = false;
+};
+
+const prepareGridItems = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (!('nodeName' in child) || child.nodeName === '#text') continue;
+		const element = child as DOMElement;
+		if (isGrid(node) && element.yogaNode) {
+			element.yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+			element.internal_gridItem = true;
+		} else {
+			resetGridItem(element);
+		}
+		prepareGridItems(element);
+	}
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode;
+	if (!yogaNode || !isGrid(node)) return;
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	let columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{type: 'auto'}];
+	let rows = parseTracks(node.style.gridTemplateRows);
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const placements: Array<{node: DOMElement; column: Placement; row: Placement}> = [];
+	const occupied = new Set<string>();
+	let cursor = 0;
+	for (const child of children) {
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		let resolvedColumn = column;
+		let resolvedRow = row;
+		if (!resolvedColumn || !resolvedRow) {
+			while (occupied.has(`${Math.floor(cursor / columns.length)}:${cursor % columns.length}`)) cursor++;
+			resolvedRow ??= {start: Math.floor(cursor / columns.length), end: Math.floor(cursor / columns.length) + 1};
+			resolvedColumn ??= {start: cursor % columns.length, end: cursor % columns.length + 1};
+		}
+		for (let rowIndex = resolvedRow.start; rowIndex < resolvedRow.end; rowIndex++) for (let columnIndex = resolvedColumn.start; columnIndex < resolvedColumn.end; columnIndex++) occupied.add(`${rowIndex}:${columnIndex}`);
+		cursor++;
+		placements.push({node: child, column: resolvedColumn, row: resolvedRow});
+	}
+	const rowCount = Math.max(rows.length, ...placements.map(placement => placement.row.end), 0);
+	while (rows.length < rowCount) rows.push({type: 'auto'});
+	const contentWidth = yogaNode.getComputedWidth() - yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const autoColumnSizes = columns.map(() => 0);
+	for (const placement of placements) {
+		if (placement.column.end - placement.column.start !== 1) continue;
+		placement.node.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+		autoColumnSizes[placement.column.start] = Math.max(autoColumnSizes[placement.column.start], placement.node.yogaNode!.getComputedWidth());
+	}
+	const columnSizes = resolveTracks(columns, contentWidth - Math.max(0, columns.length - 1) * columnGap, autoColumnSizes);
+	const autoRowSizes = rows.map(() => 0);
+	for (const placement of placements) {
+		const width = spanSize(columnSizes, placement.column.start, placement.column.end, columnGap);
+		placement.node.yogaNode!.setWidth(width);
+		placement.node.yogaNode!.calculateLayout(width, undefined, Yoga.DIRECTION_LTR);
+		if (placement.row.end - placement.row.start === 1) autoRowSizes[placement.row.start] = Math.max(autoRowSizes[placement.row.start], placement.node.yogaNode!.getComputedHeight());
+	}
+	const contentHeight = yogaNode.getComputedHeight() - yogaNode.getComputedPadding(Yoga.EDGE_TOP) - yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - yogaNode.getComputedBorder(Yoga.EDGE_TOP) - yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const rowSizes = resolveTracks(rows, node.style.height === undefined ? autoRowSizes.reduce((total, size) => total + size, 0) + Math.max(0, rows.length - 1) * rowGap : contentHeight - Math.max(0, rows.length - 1) * rowGap, autoRowSizes);
+	if (node.style.height === undefined) yogaNode.setHeight(rowSizes.reduce((total, size) => total + size, 0) + Math.max(0, rowSizes.length - 1) * rowGap + yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+	for (const placement of placements) {
+		const child = placement.node.yogaNode!;
+		child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column.start]);
+		child.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row.start]);
+		child.setWidth(spanSize(columnSizes, placement.column.start, placement.column.end, columnGap));
+		child.setHeight(spanSize(rowSizes, placement.row.start, placement.row.end, rowGap));
+	}
+};
+
+const applyGridLayout = (root: DOMElement): void => {
+	prepareGridItems(root);
+	const visit = (node: DOMElement): void => {
+		layoutGrid(node);
+		for (const child of node.childNodes) if (child.nodeName !== '#text') visit(child as DOMElement);
+	};
+	visit(root);
+};
+
+export {applyGridLayout, prepareGridItems};
